class Solution {
public:
    int search(vector<int>& nums) {
        int low = 0, high = nums.size() - 1, target;
        cin >> target;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (nums[mid] == target) {
                while (mid > 0 && nums[mid-1] == target) {
                    mid--;
                }
                return mid;
            } else if (nums[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return -1;
    }
};
int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    int ans = Solution().search(nums);
    cout << ans << endl;
    return 0;
}

