class Solution:
    def search(self, nums):
        n = int(input())
        nums = list(map(int, input().split()))
        low = 0
        high = len(nums) - 1
        target = int(input())
        while low <= high:
            mid = low + (high - low) // 2
            if nums[mid] == target:
                while mid > 0 and nums[mid - 1] == target:
                    mid -= 1
                return mid
            elif nums[mid] < target:
                low = mid + 1
            else:
                high = mid - 1
        return -1

